// Run:  npm install redux   then   node counter.js
const { createStore } = require('redux');

// A reducer is a pure function: (state, action) -> next state
function counter(state = 0, action) {
  switch (action.type) {
    case 'INCREMENT': return state + 1;
    case 'DECREMENT': return state - 1;
    default: return state;
  }
}

const store = createStore(counter);

// Subscribe: react to every state change
store.subscribe(() => console.log('state is now', store.getState()));

// Dispatch actions — the only way to change state
store.dispatch({ type: 'INCREMENT' }); // 1
store.dispatch({ type: 'INCREMENT' }); // 2
store.dispatch({ type: 'DECREMENT' }); // 1

// Run:  npm install rxjs   then   node streams.js
const { of, interval } = require('rxjs');
const { map, filter, take } = require('rxjs/operators');

// A synchronous stream of values, transformed like an array
of(1, 2, 3, 4, 5)
  .pipe(
    filter(x => x % 2 === 1),  // keep odds
    map(x => x * 10)           // scale them
  )
  .subscribe(x => console.log('value:', x)); // 10, 30, 50

// An asynchronous stream: one number every 300ms, but only the first 3
interval(300)
  .pipe(take(3))
  .subscribe({
    next: x => console.log('tick:', x),
    complete: () => console.log('done ticking'),
  });

