// Run:  npm install graphql   then   node server.js
// This doesn't start a network server — it runs a query against a schema
// in-process and prints the result, which is the clearest way to see GraphQL.
const { buildSchema, graphql } = require('graphql');

// 1. Define the schema (the type system + entry points)
const schema = buildSchema(`
  type Book { title: String, author: String }
  type Query {
    hello: String
    books: [Book]
  }
`);

// 2. Resolvers: functions that produce the data for each field
const root = {
  hello: () => 'Hello, GraphQL!',
  books: () => [
    { title: 'Dune', author: 'Herbert' },
    { title: 'Neuromancer', author: 'Gibson' },
  ],
};

// 3. Ask for exactly the fields we want
const query = `{ hello  books { title } }`;

graphql({ schema, source: query, rootValue: root })
  .then(result => console.log(JSON.stringify(result.data, null, 2)));

