// Prisma schema: datasource + generator + your data models
datasource db {
  provider = "sqlite"
  url      = "file:./dev.db"
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id    Int     @id @default(autoincrement())
  email String  @unique
  name  String?
  posts Post[]
}

model Post {
  id       Int     @id @default(autoincrement())
  title    String
  published Boolean @default(false)
  author   User    @relation(fields: [authorId], references: [id])
  authorId Int
}

// Run AFTER: npm install && npx prisma db push && npx prisma generate
const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

async function main() {
  // Create a user with a nested post
  const alice = await prisma.user.create({
    data: {
      email: 'alice@example.com',
      name: 'Alice',
      posts: { create: [{ title: 'Hello Prisma', published: true }] },
    },
    include: { posts: true },
  });
  console.log('created:', alice);

  const all = await prisma.user.findMany({ include: { posts: true } });
  console.log('all users:', JSON.stringify(all, null, 2));
}

main().finally(() => prisma.$disconnect());

